#!/usr/bin/env node

/**
 * Codestral - AI Terminal Assistant
 * Main CLI entry point
 */

import ConfigManager from '../src/config/ConfigManager.js';
import MistralClient from '../src/ai/MistralClient.js';
import TerminalInterface from '../src/cli/TerminalInterface.js';
import InputParser from '../src/parser/InputParser.js';
import MentionResolver from '../src/mentions/MentionResolver.js';
import ContextManager from '../src/context/ContextManager.js';
import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import SearchEngine from '../src/search/SearchEngine.js';
import CodebaseIndexer from '../src/indexer/CodebaseIndexer.js';
import CommandExecutor from '../src/executor/CommandExecutor.js';
import AgentOrchestrator from '../src/agent/AgentOrchestrator.js';
import ApprovalManager from '../src/agent/ApprovalManager.js';
import ToolRegistry from '../src/tools/ToolRegistry.js';
import logger from '../src/utils/logger.js';
import ErrorHandler from '../src/utils/ErrorHandler.js';
import WebSetupServer from '../src/setup/WebSetupServer.js';
import chalk from 'chalk';

// Import all tool handlers
import {
  createReadFileHandler, readFileSchema,
  createWriteFileHandler, writeFileSchema,
  createListDirectoryHandler, listDirectorySchema,
  createSearchCodeHandler, searchCodeSchema,
  createExecuteCommandHandler, executeCommandSchema,
  createReplaceInFileHandler, replaceInFileSchema,
  createCreateDirectoryHandler, createDirectorySchema,
  createCreateMultipleFilesHandler, createMultipleFilesSchema,
  createGetProjectTemplateHandler, getProjectTemplateSchema,
  createPlanProjectHandler, planProjectSchema,
  createApproveProjectHandler, approveProjectSchema
} from '../src/tools/handlers/index.js';

/**
 * Main application class that orchestrates all components
 */
class CodestralApp {
  constructor() {
    this.config = null;
    this.configManager = null;
    this.mistralClient = null;
    this.terminal = null;
    this.inputParser = null;
    this.mentionResolver = null;
    this.contextManager = null;
    this.fileSystemManager = null;
    this.searchEngine = null;
    this.codebaseIndexer = null;
    this.commandExecutor = null;
    this.toolRegistry = null;
    this.approvalManager = null;
    this.agentOrchestrator = null;
    this.errorHandler = null;
    this.isRunning = false;
  }

  /**
   * Initialize all components
   */
  async initialize() {
    try {
      // Initialize configuration manager
      this.configManager = new ConfigManager();

      // Try to load existing configuration
      try {
        this.config = await this.configManager.load();

        // If config exists but API key is empty, run setup
        if (!this.config.mistral.apiKey || this.config.mistral.apiKey === '') {
          await this.runWebSetup();
        }
      } catch (error) {
        // No config file exists - this is first-time setup
        await this.runWebSetup();
      }

      // Initialize error handler
      this.errorHandler = new ErrorHandler(logger);

      // Initialize file system manager
      this.fileSystemManager = new FileSystemManager(
        process.cwd(),
        this.config.files.ignorePatterns
      );
      await this.fileSystemManager.loadGitignore();

      // Initialize terminal interface
      this.terminal = new TerminalInterface({
        syntaxHighlight: this.config.ui.syntaxHighlight,
        theme: this.config.ui.theme,
        debug: this.config.logging.level === 'debug',
        autonomyMode: this.config.agent.autonomyMode,
        model: this.config.mistral.model
      });

      // Initialize input parser
      this.inputParser = new InputParser();

      // Initialize mention resolver
      this.mentionResolver = new MentionResolver(this.fileSystemManager, {
        maxFileSize: this.config.files.maxFileSize
      });

      // Initialize context manager
      this.contextManager = new ContextManager(this.config.context.maxTokens);

      // Initialize Mistral AI client
      this.mistralClient = new MistralClient(this.config.mistral.apiKey, {
        model: this.config.mistral.model,
        maxTokens: this.config.mistral.maxTokens,
        temperature: this.config.mistral.temperature
      });

      // Initialize codebase indexer
      this.codebaseIndexer = new CodebaseIndexer(
        process.cwd(),
        this.fileSystemManager
      );
      await this.codebaseIndexer.buildIndex();

      // Initialize search engine
      this.searchEngine = new SearchEngine(this.codebaseIndexer);

      // Initialize command executor
      this.commandExecutor = new CommandExecutor({
        timeout: 30000, // 30 second timeout
        maxBuffer: 1024 * 1024 // 1MB buffer
      });

      // Initialize tool registry
      this.toolRegistry = new ToolRegistry(
        this.fileSystemManager,
        this.searchEngine,
        this.commandExecutor
      );
      this._registerAllTools();

      // Initialize approval manager
      this.approvalManager = new ApprovalManager(
        this.config,
        this.terminal
      );

      // Initialize agent orchestrator
      this.agentOrchestrator = new AgentOrchestrator(
        this.mistralClient,
        this.toolRegistry,
        this.approvalManager,
        {
          maxToolCalls: this.config.agent?.maxToolCalls || 10,
          maxIterations: 20,
          streamResponses: true,
          displayToolCalls: true
        }
      );

      return true;
    } catch (error) {
      logger.error('Failed to initialize application', error);
      throw error;
    }
  }

  /**
   * Start the main application loop (REPL)
   */
  async start() {
    try {
      // Initialize components
      await this.initialize();

      // Start terminal interface
      await this.terminal.start();

      // Set up interrupt handler
      this.terminal.handleInterrupt(async () => {
        await this.shutdown();
      });

      this.isRunning = true;

      // Main REPL loop
      while (this.isRunning) {
        try {
          // Prompt for user input
          const userInput = await this.terminal.prompt();

          // Handle null input (Ctrl+C or empty)
          if (userInput === null || userInput === '') {
            continue;
          }

          // Process the input
          await this.processInput(userInput);

        } catch (error) {
          // Handle errors in the loop
          logger.error('Error in main loop', error);
          const errorMessage = this.errorHandler.handle(error, { context: 'main_loop' });
          this.terminal.displayError(errorMessage);
        }
      }

    } catch (error) {
      logger.error('Fatal error in application', error);
      console.error(chalk.red('\n✗ Fatal error:'), error.message);
      process.exit(1);
    }
  }

  /**
   * Process user input
   * @param {string} input - User input string
   */
  async processInput(input) {
    try {
      // Parse the input
      const parsed = this.inputParser.parse(input);
      logger.debug('Parsed input', { parsed });

      // Handle special commands
      if (parsed.isCommand) {
        await this.handleCommand(parsed.command);
        return;
      }

      // Handle regular conversation
      await this.handleConversation(parsed);

    } catch (error) {
      logger.error('Error processing input', error);
      throw error;
    }
  }

  /**
   * Handle special commands
   * @param {Object} command - Parsed command object
   */
  async handleCommand(command) {
    if (!command.isSupported) {
      this.terminal.displayWarning(`Unknown command: /${command.name}`);
      this.terminal.display('Type /help for available commands.');
      return;
    }

    logger.info(`Executing command: /${command.name}`, { args: command.args });

    switch (command.name) {
      case 'help':
        this.showHelp();
        break;

      case 'clear':
        this.contextManager.clear();
        this.terminal.displaySuccess('Context cleared');
        logger.info('Context cleared by user');
        break;

      case 'files':
        this.showFilesInContext();
        break;

      case 'config':
        this.configManager.displayConfig();
        break;

      case 'setup':
        await this.runSetup();
        break;

      case 'set':
        await this.handleSetCommand(command.args);
        break;

      case 'mode':
        this.handleModeCommand(command.args);
        break;

      case 'tools':
        this.showAvailableTools();
        break;

      case 'search':
        await this.handleSearchCommand(command.args);
        break;

      default:
        this.terminal.displayWarning(`Command not yet implemented: /${command.name}`);
    }
  }

  /**
   * Show help message
   */
  showHelp() {
    console.log(chalk.bold.cyan('\n📚 Available Commands\n'));
    console.log(chalk.bold('/help') + chalk.gray('     - Show this help message'));
    console.log(chalk.bold('/clear') + chalk.gray('    - Clear conversation context'));
    console.log(chalk.bold('/files') + chalk.gray('    - Show files currently in context'));
    console.log(chalk.bold('/config') + chalk.gray('   - Display current configuration'));
    console.log(chalk.bold('/setup') + chalk.gray('    - Run configuration setup wizard'));
    console.log(chalk.bold('/set') + chalk.gray(' <key> <value> - Update a configuration value'));
    console.log(chalk.bold('/mode') + chalk.gray(' [mode] - View or change autonomy mode (safe/autonomous/full)'));
    console.log(chalk.bold('/tools') + chalk.gray('    - List available AI tools'));
    console.log(chalk.bold('/search') + chalk.gray(' <query> - Search through codebase'));
    console.log();
    console.log(chalk.bold.cyan('💡 Tips\n'));
    console.log(chalk.gray('• Use @filename to mention files in your prompts'));
    console.log(chalk.gray('• The AI can autonomously use tools based on your autonomy mode'));
    console.log(chalk.gray('• Press Ctrl+C to exit'));
    console.log(chalk.gray('• Use arrow keys to navigate command history'));
    console.log();
  }

  /**
   * Show files currently in context
   */
  showFilesInContext() {
    const files = this.contextManager.getAllFileContexts();

    if (files.length === 0) {
      this.terminal.displayInfo('No files currently in context');
      return;
    }

    console.log(chalk.bold.cyan(`\n📁 Files in Context (${files.length})\n`));

    files.forEach((file, index) => {
      console.log(chalk.cyan(`${index + 1}. `) + chalk.white(file.path));
      console.log(chalk.gray(`   Language: ${file.language}, Size: ${file.size} bytes`));
    });

    console.log();
  }

  /**
   * Run web-based setup
   */
  async runWebSetup() {
    try {
      console.log(chalk.cyan('\n╔════════════════════════════════════════════════════════════╗'));
      console.log(chalk.cyan('║') + chalk.bold.white('     Welcome to Codestral AI Terminal Assistant!      ') + chalk.cyan('║'));
      console.log(chalk.cyan('╚════════════════════════════════════════════════════════════╝\n'));

      console.log(chalk.white('🎉 First-time setup\n'));
      console.log(chalk.gray('We\'ll open a web page in your browser for easy configuration.'));
      console.log(chalk.gray('This only needs to be done once!\n'));

      // Create and start web setup server
      const webSetup = new WebSetupServer(this.configManager);
      const setupData = await webSetup.start();

      // Save configuration
      this.config = this.configManager.getDefaultConfig();
      this.config.mistral.apiKey = setupData.apiKey;
      this.config.mistral.model = setupData.model;
      this.config.agent.autonomyMode = setupData.autonomyMode;

      await this.configManager.save(this.config);

      console.log(chalk.green('\n✓ Setup complete! Configuration saved.\n'));
      console.log(chalk.gray('Starting Codestral...\n'));

    } catch (error) {
      logger.error('Error in web setup', error);
      console.log(chalk.red('\n✗ Setup failed: ' + error.message));
      console.log(chalk.yellow('\nFalling back to terminal setup...\n'));

      // Fallback to terminal prompt
      const apiKey = await this.configManager.promptForApiKey();
      this.config = this.configManager.getDefaultConfig();
      this.config.mistral.apiKey = apiKey;
      await this.configManager.save(this.config);

      console.log(chalk.green('\n✓ Setup complete!\n'));
    }
  }

  /**
   * Run setup wizard
   */
  async runSetup() {
    try {
      this.config = await this.configManager.runSetupWizard();

      // Reinitialize components with new config
      this.terminal.displayInfo('Reinitializing with new configuration...');
      await this.initialize();
      this.terminal.displaySuccess('Configuration updated successfully');
    } catch (error) {
      logger.error('Error running setup', error);
      this.terminal.displayError('Failed to update configuration', error);
    }
  }

  /**
   * Handle /set command
   * @param {string} args - Command arguments
   */
  async handleSetCommand(args) {
    if (!args) {
      this.terminal.displayWarning('Usage: /set <key> <value>');
      this.terminal.display('Example: /set mistral.temperature 0.8');
      return;
    }

    const parts = args.split(/\s+/);
    if (parts.length < 2) {
      this.terminal.displayWarning('Usage: /set <key> <value>');
      return;
    }

    const key = parts[0];
    const value = parts.slice(1).join(' ');

    try {
      await this.configManager.updateConfig(key, value);

      // Reload config
      this.config = await this.configManager.load();

      // Reinitialize if needed (e.g., API key changed)
      if (key.startsWith('mistral.')) {
        this.terminal.displayInfo('Reinitializing AI client and agent...');
        this.mistralClient = new MistralClient(this.config.mistral.apiKey, {
          model: this.config.mistral.model,
          maxTokens: this.config.mistral.maxTokens,
          temperature: this.config.mistral.temperature
        });

        // Reinitialize agent orchestrator with new client
        this.agentOrchestrator = new AgentOrchestrator(
          this.mistralClient,
          this.toolRegistry,
          this.approvalManager,
          {
            maxToolCalls: this.config.agent?.maxToolCalls || 10,
            maxIterations: 20,
            streamResponses: true,
            displayToolCalls: true
          }
        );
      }

      // Reinitialize approval manager if agent config changed
      if (key.startsWith('agent.')) {
        this.terminal.displayInfo('Updating agent configuration...');
        this.approvalManager = new ApprovalManager(
          this.config,
          this.terminal
        );

        this.agentOrchestrator = new AgentOrchestrator(
          this.mistralClient,
          this.toolRegistry,
          this.approvalManager,
          {
            maxToolCalls: this.config.agent?.maxToolCalls || 10,
            maxIterations: 20,
            streamResponses: true,
            displayToolCalls: true
          }
        );
      }
    } catch (error) {
      logger.error('Error updating config', error);
      this.terminal.displayError(`Failed to update configuration: ${error.message}`);
    }
  }

  /**
   * Register all available tools with the tool registry
   * @private
   */
  _registerAllTools() {
    // Register read_file tool
    this.toolRegistry.registerTool(
      'read_file',
      readFileSchema,
      createReadFileHandler(this.fileSystemManager)
    );

    // Register write_file tool
    this.toolRegistry.registerTool(
      'write_file',
      writeFileSchema,
      createWriteFileHandler(this.fileSystemManager)
    );

    // Register list_directory tool
    this.toolRegistry.registerTool(
      'list_directory',
      listDirectorySchema,
      createListDirectoryHandler(this.fileSystemManager)
    );

    // Register search_code tool
    this.toolRegistry.registerTool(
      'search_code',
      searchCodeSchema,
      createSearchCodeHandler(this.searchEngine)
    );

    // Register execute_command tool
    this.toolRegistry.registerTool(
      'execute_command',
      executeCommandSchema,
      createExecuteCommandHandler(this.commandExecutor)
    );

    // Register replace_in_file tool
    this.toolRegistry.registerTool(
      'replace_in_file',
      replaceInFileSchema,
      createReplaceInFileHandler(this.fileSystemManager)
    );

    // Register create_directory tool
    this.toolRegistry.registerTool(
      'create_directory',
      createDirectorySchema,
      createCreateDirectoryHandler(this.fileSystemManager)
    );

    // Register create_multiple_files tool
    this.toolRegistry.registerTool(
      'create_multiple_files',
      createMultipleFilesSchema,
      createCreateMultipleFilesHandler(this.fileSystemManager)
    );

    // Register get_project_template tool
    this.toolRegistry.registerTool(
      'get_project_template',
      getProjectTemplateSchema,
      createGetProjectTemplateHandler()
    );

    // Register plan_project tool
    this.toolRegistry.registerTool(
      'plan_project',
      planProjectSchema,
      createPlanProjectHandler()
    );

    // Register approve_project tool
    this.toolRegistry.registerTool(
      'approve_project',
      approveProjectSchema,
      createApproveProjectHandler(this.fileSystemManager)
    );
  }

  /**
   * Handle regular conversation with AI using agentic workflow
   * @param {Object} parsed - Parsed input object
   */
  async handleConversation(parsed) {
    try {
      // Step 1: Resolve any @-mentions to file paths
      let mentionedFiles = [];
      if (parsed.mentions.length > 0) {
        logger.debug('Resolving mentions', { mentions: parsed.mentions });
        this.terminal.showSpinner('Resolving file mentions...');

        const resolved = await this.mentionResolver.resolve(parsed.mentions);

        // Collect all resolved paths
        for (const result of resolved) {
          if (result.error) {
            this.terminal.hideSpinner();
            this.terminal.displayWarning(`Could not resolve @${result.mention}: ${result.error}`);

            if (result.suggestions && result.suggestions.length > 0) {
              console.log(chalk.gray('Did you mean:'));
              result.suggestions.forEach(s => {
                console.log(chalk.gray(`  • ${s.path}`));
              });
            }
            continue;
          }

          mentionedFiles.push(...result.resolvedPaths);
        }

        this.terminal.hideSpinner();
        logger.info(`Resolved ${mentionedFiles.length} files from mentions`);
      }

      // Step 2: Read contents of mentioned files
      let fileContents = [];
      if (mentionedFiles.length > 0) {
        this.terminal.showSpinner(`Reading ${mentionedFiles.length} file(s)...`);

        fileContents = await this.mentionResolver.readMentionedFiles(mentionedFiles);

        // Display warnings for files that couldn't be read
        for (const file of fileContents) {
          if (file.error) {
            this.terminal.hideSpinner();
            this.terminal.displayWarning(`Could not read ${file.path}: ${file.error}`);
          } else if (file.warning) {
            this.terminal.hideSpinner();
            this.terminal.displayWarning(file.warning);
          }
        }

        this.terminal.hideSpinner();

        // Filter out files with errors
        fileContents = fileContents.filter(f => f.content !== null);

        if (fileContents.length > 0) {
          this.terminal.displayInfo(`Loaded ${fileContents.length} file(s) into context`);
        }
      }

      // Step 3: Add files to context manager
      for (const file of fileContents) {
        this.contextManager.addFileContext(file.path, file.content, {
          size: file.size
        });
      }

      // Step 4: Build the message with file context
      let userMessage = parsed.sanitized;

      // If files were mentioned, add their contents to the message
      if (fileContents.length > 0) {
        const fileContextText = fileContents.map(file => {
          return `\n\n--- File: ${file.path} ---\n${file.content}\n--- End of ${file.path} ---`;
        }).join('\n');

        userMessage = `${parsed.sanitized}\n\nHere are the mentioned files:${fileContextText}`;
      }

      // Step 5: Check if context is near token limit and truncate if needed
      if (this.contextManager.isNearTokenLimit(0.85)) {
        logger.info('Context near token limit, truncating...');
        const removed = this.contextManager.truncate({
          keepSystemMessages: true,
          keepRecentCount: 10,
          targetTokens: this.config.context.maxTokens * 0.7
        });

        if (removed.length > 0) {
          logger.info(`Truncated ${removed.length} messages from context`);
        }
      }

      // Step 6: Process message through agent orchestrator
      try {
        const result = await this.agentOrchestrator.processMessage(
          userMessage,
          this.contextManager,
          {
            onToolCall: this._handleToolCallDisplay.bind(this),
            onToolResult: this._handleToolResultDisplay.bind(this),
            onResponse: this._handleResponseDisplay.bind(this)
          }
        );

        // Display final response if not already displayed
        if (result.content && !result.displayed) {
          console.log(chalk.cyan('\n🤖 Assistant: '));
          console.log(result.content);
          console.log('');
        }

      } catch (error) {
        throw error;
      }

    } catch (error) {
      logger.error('Error in conversation handling', error);

      // Use error handler to get user-friendly message
      const errorMessage = this.errorHandler.handle(error, {
        context: 'conversation',
        input: parsed.original
      });

      this.terminal.displayError(errorMessage);
    }
  }

  /**
   * Handle mode command - change or display autonomy mode
   * @param {string} args - Command arguments
   */
  handleModeCommand(args) {
    if (!this.approvalManager) {
      this.terminal.displayError('Approval manager not initialized');
      return;
    }

    this.approvalManager.handleModeCommand(args);
  }

  /**
   * Show available AI tools
   */
  showAvailableTools() {
    if (!this.toolRegistry) {
      this.terminal.displayError('Tool registry not initialized');
      return;
    }

    const toolNames = this.toolRegistry.getToolNames();

    console.log(chalk.bold.cyan(`\n🔧 Available AI Tools (${toolNames.length})\n`));

    toolNames.forEach((toolName, index) => {
      const tool = this.toolRegistry.getToolByName(toolName);
      console.log(chalk.cyan(`${index + 1}. `) + chalk.white(toolName));
      if (tool && tool.schema && tool.schema.description) {
        console.log(chalk.gray(`   ${tool.schema.description}`));
      }
    });

    console.log();
    console.log(chalk.gray('The AI can use these tools autonomously based on your current autonomy mode.'));
    console.log(chalk.gray('Use /mode to view or change your autonomy settings.'));
    console.log();
  }

  /**
   * Handle search command
   * @param {string} args - Search query
   */
  async handleSearchCommand(args) {
    if (!args || args.trim() === '') {
      this.terminal.displayWarning('Usage: /search <query>');
      this.terminal.display('Example: /search "function handleUser"');
      return;
    }

    if (!this.searchEngine) {
      this.terminal.displayError('Search engine not initialized');
      return;
    }

    try {
      this.terminal.showSpinner(`Searching for "${args}"...`);

      const results = await this.searchEngine.search(args, {
        maxResults: 20,
        contextLines: 2
      });

      this.terminal.hideSpinner();

      if (results.length === 0) {
        this.terminal.displayInfo(`No results found for "${args}"`);
        return;
      }

      console.log(chalk.bold.cyan(`\n🔍 Search Results for "${args}" (${results.length})\n`));

      results.forEach((result, index) => {
        console.log(chalk.cyan(`${index + 1}. `) + chalk.white(result.filePath) + chalk.gray(`:${result.lineNumber}`));
        console.log(chalk.gray(`   ${result.line.trim()}`));

        if (result.context && result.context.before && result.context.before.length > 0) {
          result.context.before.forEach(line => {
            console.log(chalk.gray(`   ${line.trim()}`));
          });
        }

        if (result.context && result.context.after && result.context.after.length > 0) {
          result.context.after.forEach(line => {
            console.log(chalk.gray(`   ${line.trim()}`));
          });
        }

        console.log();
      });

    } catch (error) {
      this.terminal.hideSpinner();
      logger.error('Search command failed', error);
      this.terminal.displayError(`Search failed: ${error.message}`);
    }
  }

  /**
   * Handle tool call display callback
   * @param {string} toolName - Name of the tool being called
   * @param {Object} parameters - Tool parameters
   * @param {string} toolCallId - Tool call ID
   * @private
   */
  _handleToolCallDisplay(toolName, parameters, toolCallId) {
    // Hide any existing spinner
    this.terminal.hideSpinner();

    // Display tool call header with icon and formatting
    console.log(chalk.bold.cyan('\n╭─────────────────────────────────────────────────────────────╮'));
    console.log(chalk.bold.cyan('│') + chalk.bold.yellow(` 🔧 AI Tool Execution: ${toolName}`.padEnd(58)) + chalk.bold.cyan('│'));
    console.log(chalk.bold.cyan('╰─────────────────────────────────────────────────────────────╯'));

    // Display parameters if they exist
    if (parameters && Object.keys(parameters).length > 0) {
      console.log(chalk.bold.white('\nParameters:'));
      Object.entries(parameters).forEach(([key, value]) => {
        let displayValue = value;

        // Format different types of values
        if (typeof value === 'string') {
          if (value.length > 300) {
            displayValue = value.substring(0, 300) + chalk.gray('... [truncated]');
          }
          // Highlight file paths
          if (key === 'path' || key === 'filePath') {
            displayValue = chalk.cyan(displayValue);
          }
        } else if (typeof value === 'object') {
          displayValue = JSON.stringify(value, null, 2);
          if (displayValue.length > 300) {
            displayValue = displayValue.substring(0, 300) + chalk.gray('... [truncated]');
          }
        } else if (typeof value === 'boolean') {
          displayValue = value ? chalk.green('true') : chalk.red('false');
        }

        console.log(chalk.white(`  ${key}: `) + chalk.gray(displayValue));
      });
    }

    // Show execution spinner
    this.terminal.showSpinner(`Executing ${toolName}...`);
  }

  /**
   * Handle tool result display callback
   * @param {Object} result - Tool execution result
   * @private
   */
  _handleToolResultDisplay(result) {
    // Hide spinner
    this.terminal.hideSpinner();

    if (result.success) {
      // Success header
      console.log(chalk.green.bold(`\n✓ Tool "${result.toolName}" completed successfully`));

      // Display result with appropriate formatting
      if (result.result) {
        this._displayToolResult(result.toolName, result.result);
      }
    } else {
      // Error header
      console.log(chalk.red.bold(`\n✗ Tool "${result.toolName}" failed`));
      console.log(chalk.red(`Error: ${result.error}`));
    }

    // Add separator
    console.log(chalk.gray('─'.repeat(60)));
    console.log();
  }

  /**
   * Display tool result with appropriate formatting based on tool type
   * @param {string} toolName - Name of the tool
   * @param {*} result - Tool result
   * @private
   */
  _displayToolResult(toolName, result) {
    if (!result) return;

    switch (toolName) {
      case 'read_file':
        this._displayFileContent(result);
        break;

      case 'list_directory':
        this._displayDirectoryListing(result);
        break;

      case 'search_code':
        this._displaySearchResults(result);
        break;

      case 'execute_command':
        this._displayCommandOutput(result);
        break;

      case 'write_file':
      case 'replace_in_file':
      case 'create_directory':
        this._displayFileOperation(result);
        break;

      case 'create_multiple_files':
        this._displayMultiFileOperation(result);
        break;

      default:
        this._displayGenericResult(result);
    }
  }

  /**
   * Display file content with syntax highlighting
   * @param {string} content - File content
   * @private
   */
  _displayFileContent(content) {
    if (typeof content === 'string') {
      const lines = content.split('\n');
      const displayLines = lines.length > 20 ? lines.slice(0, 20) : lines;

      console.log(chalk.gray('\nFile content:'));
      console.log(chalk.gray('─'.repeat(40)));

      displayLines.forEach((line, index) => {
        console.log(chalk.gray(`${(index + 1).toString().padStart(3)}: `) + line);
      });

      if (lines.length > 20) {
        console.log(chalk.gray(`... and ${lines.length - 20} more lines`));
      }

      console.log(chalk.gray('─'.repeat(40)));
    }
  }

  /**
   * Display directory listing
   * @param {Array} files - Array of file objects
   * @private
   */
  _displayDirectoryListing(files) {
    if (Array.isArray(files)) {
      console.log(chalk.gray(`\nDirectory contents (${files.length} items):`));

      files.slice(0, 15).forEach(file => {
        const icon = file.type === 'directory' ? '📁' : '📄';
        const name = file.type === 'directory' ? chalk.blue(file.name) : chalk.white(file.name);
        const size = file.size ? chalk.gray(` (${this._formatFileSize(file.size)})`) : '';
        console.log(`  ${icon} ${name}${size}`);
      });

      if (files.length > 15) {
        console.log(chalk.gray(`  ... and ${files.length - 15} more items`));
      }
    }
  }

  /**
   * Display search results
   * @param {Array} results - Search results
   * @private
   */
  _displaySearchResults(results) {
    if (Array.isArray(results)) {
      console.log(chalk.gray(`\nSearch results (${results.length} matches):`));

      results.slice(0, 10).forEach((result, index) => {
        console.log(chalk.cyan(`${index + 1}. `) + chalk.white(result.filePath) + chalk.gray(`:${result.lineNumber}`));
        if (result.line) {
          console.log(chalk.gray(`   ${result.line.trim()}`));
        }
      });

      if (results.length > 10) {
        console.log(chalk.gray(`... and ${results.length - 10} more matches`));
      }
    }
  }

  /**
   * Display command execution output
   * @param {Object} output - Command output
   * @private
   */
  _displayCommandOutput(output) {
    if (typeof output === 'object' && output.stdout) {
      console.log(chalk.gray('\nCommand output:'));
      console.log(chalk.gray('─'.repeat(40)));
      console.log(output.stdout);

      if (output.stderr) {
        console.log(chalk.red('\nError output:'));
        console.log(chalk.red(output.stderr));
      }

      console.log(chalk.gray('─'.repeat(40)));
    } else if (typeof output === 'string') {
      console.log(chalk.gray('\nOutput:'));
      console.log(output);
    }
  }

  /**
   * Display file operation result
   * @param {string} result - Operation result message
   * @private
   */
  _displayFileOperation(result) {
    if (typeof result === 'string') {
      console.log(chalk.green(`\n${result}`));
    }
  }

  /**
   * Display multi-file operation result
   * @param {Object} result - Multi-file operation result
   * @private
   */
  _displayMultiFileOperation(result) {
    if (typeof result === 'object' && result.filesCreated) {
      console.log(chalk.green(`\nCreated ${result.filesCreated.length} files:`));
      result.filesCreated.forEach(file => {
        console.log(chalk.gray(`  ✓ ${file}`));
      });
    } else if (typeof result === 'string') {
      console.log(chalk.green(`\n${result}`));
    }
  }

  /**
   * Display generic result
   * @param {*} result - Generic result
   * @private
   */
  _displayGenericResult(result) {
    if (typeof result === 'string') {
      if (result.length < 1000) {
        console.log(chalk.gray(`\nResult: ${result}`));
      } else {
        console.log(chalk.gray(`\nResult: ${result.substring(0, 1000)}... [truncated]`));
      }
    } else if (typeof result === 'object') {
      const resultStr = JSON.stringify(result, null, 2);
      if (resultStr.length < 1000) {
        console.log(chalk.gray(`\nResult:`));
        console.log(chalk.gray(resultStr));
      } else {
        console.log(chalk.gray('\nResult: [Large object - details omitted]'));
      }
    }
  }

  /**
   * Format file size for display
   * @param {number} bytes - File size in bytes
   * @returns {string} Formatted file size
   * @private
   */
  _formatFileSize(bytes) {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    return `${(bytes / (1024 * 1024 * 1024)).toFixed(1)} GB`;
  }

  /**
   * Handle response display callback
   * @param {string} content - Response content
   * @param {Object} response - Full response object
   * @private
   */
  _handleResponseDisplay(content, response) {
    // Mark as displayed so we don't show it again
    response.displayed = true;

    console.log(chalk.cyan('\n🤖 Assistant: '));
    console.log(content);
    console.log();
  }

  /**
   * Shutdown the application gracefully
   */
  async shutdown() {
    logger.info('Shutting down application');
    this.isRunning = false;

    // Stop terminal interface
    if (this.terminal) {
      this.terminal.stop();
    }

    logger.info('Application shutdown complete');
  }
}

/**
 * Main entry point
 */
async function main() {
  const app = new CodestralApp();

  try {
    await app.start();
  } catch (error) {
    console.error(chalk.red('\n✗ Application failed to start:'), error.message);
    logger.error('Application startup failed', error);
    process.exit(1);
  }
}

// Run the application
main();
